INSERT OR REPLACE INTO legal_regulations
(regulation_id, title, issuing_body, issue_date, effective_date, status, summary, full_text, keywords, source_url, applicable_scenarios)
VALUES
('LAW001', '《民法典》第496条', '全国人民代表大会', '2020-05-28', '2021-01-01', '有效', '提供格式条款的一方应遵循公平原则确定权利义务，并采取合理方式提示与对方有重大利害关系的条款。', '格式条款提供方应提示免除或者减轻其责任等与对方有重大利害关系的条款，并按要求说明。', '格式条款,提示说明义务,费用不透明,重大利害关系', 'https://www.spp.gov.cn/spp/ssmfdyflvdtpgz/202008/t20200831_478413.shtml', '费用不透明、默认授权、重要风险条款未提示'),
('LAW002', '《民法典》第670条', '全国人民代表大会', '2020-05-28', '2021-01-01', '有效', '借款利息不得预先在本金中扣除；预先扣除的，应按实际借款数额返还借款并计算利息。', '借款的利息不得预先在本金中扣除。利息预先在本金中扣除的，应当按照实际借款数额返还借款并计算利息。', '砍头息,实际到账金额,预先扣除,本金', 'https://www.spp.gov.cn/spp/ssmfdyflvdtpgz/202008/t20200831_478413.shtml', '实际到账金额低于合同本金、先扣服务费'),
('LAW003', '《民法典》第677条', '全国人民代表大会', '2020-05-28', '2021-01-01', '有效', '借款人提前返还借款的，除另有约定外，应按实际借款期间计算利息。', '借款人提前返还借款的，除当事人另有约定外，应当按照实际借款的期间计算利息。', '提前还款,提前结清,手续费,违约金', 'https://www.spp.gov.cn/spp/ssmfdyflvdtpgz/202008/t20200831_478413.shtml', '提前还款手续费、提前结清限制'),
('LAW004', '中国人民银行公告〔2021〕第3号', '中国人民银行', '2021-03-31', '2021-03-31', '有效', '所有贷款产品均应明示贷款年化利率，年化利率应以对借款人收取的全部贷款成本与实际占用本金的比例计算。', '贷款年化利率应以对借款人收取的全部贷款成本与其实际占用的贷款本金的比例计算，并折算为年化形式。', '年化利率,真实年化,全部贷款成本,IRR,费用', 'https://www.gov.cn/zhengce/zhengceku/2021-03/31/content_5597156.htm', '真实年化偏高、费用不透明、名义利率与真实成本不一致'),
('LAW005', '《消费者权益保护法实施条例》第10条', '国务院', '2024-03-15', '2024-07-01', '有效', '经营者以自动展期、自动续费等方式提供服务的，应以显著方式提请消费者注意，并在消费者接受服务前和自动展期、自动续费前提醒。', '经营者采取自动展期、自动续费等方式提供服务，应当以显著方式提请消费者注意。', '自动续费,自动扣款,显著提示,消费者权益', 'http://politics.people.com.cn/n1/2024/0320/c1001-40199070.html', '自动续费、自动扣款授权、默认勾选'),
('LAW006', '《银行保险机构消费者权益保护管理办法》第26条', '原中国银保监会', '2022-12-26', '2023-03-01', '有效', '银行保险机构不得强制捆绑、强制搭售产品或者服务。', '银行保险机构销售产品或者提供服务过程中，不得强制捆绑、强制搭售。', '捆绑销售,搭售,保险,贷款服务', 'https://www.gov.cn/gongbao/content/2023/content_5753317.html', '贷款搭售保险、会员服务、培训服务');
